return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'da_DK','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Opdater pluginet TranslatePress - Multilingual til version %1$s eller højere for at sikre, at %2$s fungerer korrekt.','Please install and activate the TranslatePress - Multilingual plugin'=>'Installer og aktiver pluginet TranslatePress - Multilingual','Install & Activate'=>'Installer og aktiver','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Opdater TranslatePress - Multilingual til version %2$s eller nyere. Din aktuelt installerede version af TranslatePress - Multilingual er ikke længere kompatibel med den aktuelle version af %1$s.','All TranslatePress functionalities are disabled until then.'=>'Alle funktionaliteter i TranslatePress er deaktiveret indtil da.','Update Now'=>'Opdater nu','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Denne TranslatePress-tilføjelse er blevet overført til hovedpluginet og bruges ikke længere. Du kan slette den.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> kræver mindst PHP-version 5.6.20+ for at køre. Det er <a href="%s">minimumskravet for den nyeste WordPress-version</a>. Kontakt din serveradministrator for at opdatere din PHP-version.','Advanced'=>'Avancerede','Settings saved.'=>'Indstillinger gemt.','Are you sure you want to remove this item?'=>'Er du sikker på, at du vil fjerne dette element?','Remove'=>'Fjern','Add'=>'Tilføj','Select...'=>'Vælg...','[%s] Low TranslatePress AI Words'=>'[%s] Lavt antal TranslatePress AI-ord','upgrade your plan or get extra AI Words'=>'opgrader din plan eller få ekstra AI-ord','upgrade your plan'=>'opgrader din plan','TranslatePress AI words are running low on your site.'=>'Der er ved at være sluppet op for TranslatePress AI-ord på dit site.','Current status: %s words remaining'=>'Aktuel status: %s ord tilbage','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Når de resterende AI-ord slipper op, vil automatisk oversættelse via TranslatePress AI blive sat på pause.','To continue translating your content, please %1$s over at %2$s'=>'For at fortsætte med at oversætte dit indhold, bedes du %1$s på %2$s','Manage Notification: %s'=>'Administrer notifikation: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Der er en ny version af %1$s tilgængelig. %2$sSe detaljer for version %3$s%4$s eller %5$sopdater nu%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Der er en ny version af %1$s tilgængelig. %2$sSe detaljer for version %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'For at aktivere opdateringer skal du %1$sindtaste din licensnøgle%2$s. Mangler du en licensnøgle? %3$sKøb en nu%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'For at aktivere opdateringer skal du gå til %1$slicenssiden%2$s og kontrollere, at du har en gyldig licens.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'For at aktivere opdateringer skal din licens fornyes. Gå til siden %1$sTranslatePress Account%2$s og log ind for at fornye.','You do not have permission to install plugin updates'=>'Du har ikke tilladelse til at installere plugin-opdateringer','Error'=>'Fejl','Your TranslatePress license key is invalid or missing.'=>'Din TranslatePress-licensnøgle er ugyldig eller mangler.','Your license key expired on %s.'=>'Din licensnøgle udløb den %s.','Your license key has been disabled.'=>'Din licensnøgle er blevet deaktiveret.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Din licensnøgle er deaktiveret for denne URL. Genaktiver den fra <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrer sites.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Licensnøglen stemmer ikke overens.</strong> Licensen, du indtastede, stemmer ikke overens med den version af TranslatePress, du har installeret.</p><p>Kontroller, at du har installeret den korrekte version til din licens fra din TranslatePress Account.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Hvis du kun har det gratis plugin installeret, men har tilføjet en betalt licens, skal du installere det betalte plugin fra din TranslatePress Account.','Your license key has reached its activation limit.'=>'Din licensnøgle har nået grænsen for aktiveringer.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Opgrader din plan for at tilføje flere sites. %1$sOpgrader nu%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Dette websted er allerede aktiveret med en gratis licens. Hvert websted kan kun bruge én gratis licens.','An error occurred, please try again.'=>'Der opstod en fejl. Prøv igen.','You have successfully activated your license'=>'Du har aktiveret din licens','Others'=>'Andre','Restrict by Language'=>'Begræns efter sprog','Exclude from Language'=>'Udeluk fra sprog','Restrict element to language'=>'Begræns element til sprog','Show this element only in one language.'=>'Vis dette element kun på et sprog.','Enable translation'=>'Aktivér oversættelse','Allow translation to the corresponding language only if the content is written in the default language.'=>'Tillad kun oversættelse til det tilsvarende sprog, hvis indholdet er skrevet på standardsproget.','Select language'=>'Vælg et sprog','Choose in which language to show this element.'=>'Vælg hvilket sprog dette element skal vises på.','Exclude element from language'=>'Udeluk element fra sprog','Exclude this element from specific languages.'=>'Udeluk dette element fra bestemte sprog.','Select languages'=>'Vælg sprog','Choose from which languages to exclude this element.'=>'Vælg hvilke sprog dette element skal udelukkes fra.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Dette element vil stadig være synligt, når du oversætter din hjemmeside via Oversættelseseditoren.','The content of this element should be written in the default language.'=>'Indholdet af dette element skal være skrevet på standardsproget.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> stødte på SQL-fejl. <a href="%s" title="View TranslatePress SQL Errors">Se fejlene</a>.','Automatic translation has been disabled.'=>'Automatisk oversættelse er blevet deaktiveret.','Dismiss this notice.'=>'Afvis denne meddelelse.','Logged errors'=>'Logget fejl','These are the most recent 5 errors logged by TranslatePress:'=>'Dette er de seneste 5 fejl logget af TranslatePress:','Yes'=>'Ja','Why are these errors occuring'=>'Hvorfor opstår disse fejl','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Hvis TranslatePress registrerer noget galt under udførelse af forespørgsler på din database, kan den deaktivere funktionen Automatisk oversættelse for at undgå yderligere opkrævning fra Google/DeepL. Automatisk oversættelse skal aktiveres manuelt, efter du har løst problemerne.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'De registrerede SQL-fejl kan opstå af forskellige årsager, herunder manglende tabeller, manglende tilladelser for SQL-brugeren til at oprette tabeller eller udføre andre handlinger, problemer efter webstedsmigrering eller ændringer af SQL-serverkonfigurationen.','What you can do in this situation'=>'Hvad du kan gøre i denne situation','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Gå til Indstillinger -> TranslatePress -> fanen Generelt og gem indstillinger. Dette vil regenerere tabellerne ved hjælp af dine nuværende SQL-indstillinger. Kontroller, om der ikke opstår flere fejl, mens du gennemser dit websted på et oversat sprog. Se på tidsstemplerne for fejlene for at sikre dig, at du ikke ser de gamle fejl. Kun de 5 seneste fejl vises.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Hvis dit problem ikke er løst, prøv følgende trin:','Create a backup of your database'=>'Opret en sikkerhedskopi af din database','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Opret en kopi af hver oversættelsestabel, hvor du støder på fejl. Du kan kopiere tabellen inden for den samme database (f.eks. trp_dictionary_en_us_es_es_COPY) -- udfør dette trin kun, hvis du vil beholde de nuværende oversættelser','Remove the trouble tables by executing the DROP function on them'=>'Fjern de problematiske tabeller ved at udføre DROP-funktionen på dem','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Gå til Indstillinger -> TranslatePress -> fanen Generelt og gem indstillinger. Dette vil regenerere tabellerne ved hjælp af din nuværende SQL-server.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopier det relevante indhold fra de duplikerede tabeller (f.eks. trp_dictionary_en_us_es_es_COPY) til den nygenererede tabel (trp_dictionary_en_us_es_es) -- udfør dette trin kun, hvis du vil beholde de nuværende oversættelser','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Test det for at se, om alt fungerer. Hvis noget gik galt, kan du gendanne sikkerhedskopien, som du oprettede i første trin. Kontroller, om der ikke opstår flere fejl, mens du gennemser dit websted på et oversat sprog. Se på tidsstemplerne for fejlene for at sikre dig, at du ikke ser de gamle fejl. Kun de 5 seneste fejl vises.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Hvis dit problem stadig ikke er løst, kan du prøve at spørge din hostingudbyder om dine fejl. Det mest almindelige problem er manglende tilladelser for SQL-brugeren, såsom tilladelsen til at oprette tabeller.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Kunne ikke installeres. Prøv igen fra <a href="%s" >Plugins-dashboardet.</a>','Active'=>'Aktiv','Permission denied.'=>'Tilladelse nægtet.','Invalid nonce.'=>'Ugyldig nonce.','Settings scope unknown.'=>'Ukendt indstillingsomfang.','Legacy disabled.'=>'Legacy deaktiveret.','Language Switcher'=>'Sprogvælger','Change language to %s'=>'Skift sprog til %s','Automatic Translation'=>'Automatisk oversættelse','DeepL'=>'DeepL','Unsupported languages'=>'Ikke-understøttede sprog','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Den valgte motor til automatisk oversættelse understøtter ikke disse sprog.<br>Du kan stadig manuelt oversætte sider på disse sprog ved hjælp af oversættelseseditoren.','API key validation failed.'=>'Validering af API-nøgle mislykkedes.','API key verification was successful.'=>'Verifikation af API-nøgle lykkedes.','Please enter your Google Translate key.'=>'Indtast din Google Translate-nøgle.','Please enter your DeepL API key.'=>'Indtast din DeepL API-nøgle.','Not TranslatePress onboarding page.'=>'Ikke TranslatePress-introside.','Step %s does not exist'=>'Trin %s findes ikke','Welcome'=>'Velkommen','Add Languages'=>'Tilføj sprog','Enable Addons'=>'Aktivér tilføjelser','Finalize'=>'Færdiggør','Exit Setup'=>'Afslut opsætning','Upgrade'=>'Opgrader','Nothing here'=>'Intet her','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Din <strong>TranslatePress</strong>-licens mangler eller er ugyldig. <br/>Du bedes %1$sregistrere din kopi%2$s for at aktivere automatisk oversættelse af dit websted via TranslatePress AI, premium-tilføjelser, automatiske opdateringer og support. Har du brug for en licensnøgle? %3$sKøb en nu%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Din <strong>TranslatePress</strong>-licens udløber den %1$s. Du bedes %2$sfornye din licens%3$s for fortsat at have adgang til automatiske oversættelser via TP AI, premium-tilføjelser, produktdownloads og automatiske opdateringer. %4$sForny nu%5$s','Error: '=>'Fejl: ','Something went wrong, please try again.'=>'Der gik noget galt. Prøv venligst igen.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Din <strong>TranslatePress</strong>-licens er udløbet. <br/>Du bedes %1$sfornye din licens%2$s for fortsat at have adgang til automatiske oversættelser via TranslatePress AI, premium-tilføjelser, produktdownloads og automatiske opdateringer. %3$sForny nu %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Licensnøglen stemmer ikke overens. Den licens, du har indtastet, stemmer ikke overens med den <strong>%1$s</strong>-version, du har installeret. <br/>Du bedes kontrollere, at du har installeret den korrekte version til din licens fra din %2$sTranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Hvis du kun har det gratis plugin installeret, men har tilføjet en betalt licens, skal du installere det betalte plugin fra din TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Du har nået aktiveringsgrænsen for din <strong>%1$s</strong>-licens. <br/>Administrer dine aktive websteder fra %2$s din konto %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Din licens er deaktiveret for denne URL. Genaktivér den fra <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrer websteder.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Automatisk oversættelse med %1$s kræver en aktiv licens. Du bedes %2$sfornye%3$s din licens eller købe en ny %4$sher%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Du bedes %1$sindtaste%2$s din licensnøgle for at aktivere automatisk oversættelse med %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Du har mindre end 5.000 TranslatePress AI-ord tilbage. For at fortsætte med automatisk at oversætte dit websted, bedes du %skøbe yderligere AI-ord med rabat fra din konto%s.',' Error: '=>' Fejl: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Dette websted er allerede aktiveret med en gratis licens. Hvert websted kan kun bruge én gratis licens. Du bedes opgradere til en premium-plan for flere TranslatePress AI-ord fra %1$s din konto %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Du har ikke en gyldig licens til <strong>TranslatePress</strong>. %1$sFå en gratis licens%2$s for at få adgang til TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NYT:</strong> Tilføjelsen <strong>Different Domain per Language</strong> er her! Boost din globale SEO og skab en lokal oplevelse med landespecifikke domæner som .de eller .fr. Opgrader til <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business eller Developer</a> for at få adgang til den + flere premium-fordele!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NYT:</strong> Tilføjelsen <strong>Different Domain per Language</strong> er her! Boost din globale SEO og skab en lokal oplevelse med landespecifikke domæner som .de eller .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Læs mere</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Den daglige kvote for maskinoversættelsestegn er overskredet. Du bedes kontrollere siden <strong>TranslatePress -> <a href="%s">Automatisk oversættelse</a></strong> for flere oplysninger.','Marketing optin'=>'Marketing-tilmelding','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Tilmeld dig vores notifikationer om sikkerheds- og funktionsopdateringer samt ikke-følsom diagnostisk sporing.','TranslatePress Preferred User Language'=>'Foretrukket brugersprog i TranslatePress','Preferred language to navigate the site'=>'Foretrukket sprog til at navigere på siden','The language is automatically set based by the last visited language by the user.'=>'Sproget indstilles automatisk baseret på brugerens sidst besøgte sprog.','Always use this language'=>'Brug altid dette sprog','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Ved at markere denne indstilling forbliver det foretrukne sprog det ovenfor valgte, uden mulighed for at blive ændret i frontend.<br>Dette sprog vil blive brugt i forskellige handlinger, såsom afsendelse af e-mail til brugeren.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Hej! Det ser ud til, at du har brugt <strong>TranslatePress</strong> et stykke tid nu til at oversætte din hjemmeside. Det er fantastisk! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Hvis du kan afsætte et øjeblik til at bedømme det på WordPress.org, vil det hjælpe os meget (og styrke min motivation).','~ Razvan, developer of TranslatePress'=>'~ Razvan, udvikler af TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Bedøm TranslatePress på WordPress.org-pluginsiden','Ok, I will gladly help!'=>'Ok, jeg hjælper gerne!','No, thanks.'=>'Nej, tak.','Full Language Names'=>'Fulde sprognavne','Short Language Names'=>'Korte sprognavne','Flags with Full Language Names'=>'Flag med fulde sprognavne','Flags with Short Language Names'=>'Flag med korte sprognavne','Only Flags'=>'Kun flag','Full Language Names No HTML'=>'Fulde sprognavne uden HTML','Bottom Right'=>'Nederst til højre','Bottom Left'=>'Nederst til venstre','Top Right'=>'Øverst til højre','Top Left'=>'Øverst til venstre','Dark'=>'Mørk','Light'=>'Lys','Deactivate'=>'Deaktiver','Activate'=>'Aktiver','Invalid language code. Please try again.'=>'Ugyldig sprogkode. Prøv igen.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Sprogkoder må kun indeholde tegnene A-Z a-z 0-9 - _. Tjek dine sprogkoder under Generelle indstillinger i TranslatePress.','Error! Duplicate URL slug values.'=>'Fejl! Duplikerede URL-slug-værdier.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Du kan ikke vælge to sprog, der har den samme <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">ISO-kode</a>, men forskellige formaliteter, da det vil føre til duplikerede <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang-tags</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Duplikeret sprog registreret.<br>Hvert sprog kan kun tilføjes én gang for at sikre præcis oversættelsesstyring.<br> Ret den duplikerede sprogindtastning og prøv igen. ','Current Language'=>'Aktuelt sprog','Opposite Language'=>'Modsatte sprog','General'=>'Generelt','Translate Site'=>'Oversæt websted','Addons'=>'Tilføjelser','License'=>'Licens','Settings'=>'Indstillinger','Activate License'=>'Aktiver licens','Pro Features'=>'Pro-funktioner','Need Help?'=>'Brug for hjælp?','Recent community discussions'=>'Seneste fællesskabsdiskussioner','Loading...'=>'Indlæser...','Unable to load forum posts'=>'Kunne ikke indlæse forumindlæg','Ask a Question'=>'Stil et spørgsmål','View All Topics'=>'Vis alle emner','by'=>'af','Have a question?'=>'Har du et spørgsmål?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Få hjælp direkte fra plugin-udviklerne, foreslå forbedringer eller del din feedback!','Tip for faster help:'=>'Tip til hurtigere hjælp:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Inkluder, hvad du prøvede, hvad du forventede, og hvad der skete. Skærmbilleder hjælper!','Toggle support chat'=>'Slå supportchat til/fra','Ask the community'=>'Spørg fællesskabet','Close'=>'Luk','Empty feed response'=>'Tomt feed-svar','Unable to parse feed'=>'Kan ikke analysere feed','Just now'=>'Lige nu','%d hour ago'=>'%d time siden' . "\0" . '%d timer siden','%d day ago'=>'%d dag siden' . "\0" . '%d dage siden','Source'=>'Kilde','Srcset'=>'Srcset','Alt attribute'=>'Alt-attribut','Title attribute'=>'Titel-attribut','Anchor link'=>'Ankerlink','Placeholder attribute'=>'Pladsholder-attribut','Submit attribute'=>'Send-attribut','Text'=>'Tekst','Video Poster'=>'Video-poster','plural form'=>'flertalsform','one'=>'en','few'=>'få','many'=>'mange','other'=>'andre','Saved'=>'Gemt','Save'=>'Gem','Saving translation...'=>'Gemmer oversættelse...','You have unsaved changes!'=>'Du har ugemte ændringer!','Discard changes'=>'Kassér ændringer','Discard All'=>'Kassér alle','Loading Strings...'=>'Indlæser strenge...','Select string to translate...'=>'Vælg streng der skal oversættes...','Close Editor'=>'Luk editor','From'=>'Fra','To'=>'Til','Add Media'=>'Tilføj medie','Other languages'=>'Andre sprog','Context'=>'Kontekst','View Website As'=>'Vis website som','Available in our Pro Versions'=>'Tilgængelig i vores Pro-versioner','Select or Upload Media'=>'Vælg eller upload medie','Use this media'=>'Brug dette medie','Translate'=>'Oversæt','Translate entire block element'=>'Oversæt hele blok-elementet','Split block to translate strings individually'=>'Opdel blok for at oversætte strenge individuelt','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Gem ændringer i oversættelsen. Genvej: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Naviger til næste streng i dropdown-listen. Genvej: CTRL(⌘) + ALT + Højre pil','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Naviger til forrige streng i dropdown-listen. Genvej: CTRL(⌘) + ALT + Venstre pil','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Kassér alle ændringer. Genvej: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Kassér ændringer i dette tekstfelt. For at kassére alle ændringer i alle tekstfelter skal du bruge genvejen: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Luk værktøjstip','Quick Intro'=>'Hurtig introduktion','Are you sure you want to split this phrase into smaller parts?'=>'Er du sikker på, at du vil opdele denne sætning i mindre dele?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Denne streng er ikke klar til oversættelse endnu. <br>Prøv igen om et øjeblik...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'For at denne indstilling virker, skal du opdatere tilføjelsen Browse as other role til den nyeste version.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'For at oversætte slugs skal du opdatere SEO Pack-tilføjelsen til den nyeste version.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Du kan tilføje et nyt sprog fra <a href="%s">Indstillinger->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Du kan dog stadig bruge TranslatePress til at <strong style="background: #f5fb9d;">redigere Gettext-strenge</strong> på din side.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Brugeroprettede strenge kan ikke redigeres, kun dem fra temaer og plugins.','Extra Translation Features'=>'Ekstra oversættelsesfunktioner','Support for 130+ Extra Languages'=>'Understøttelse af 130+ ekstra sprog','Access to TranslatePress AI'=>'Adgang til TranslatePress AI','Translate SEO Title, Description, Slug'=>'Oversæt SEO-titel, beskrivelse og slug','Publish only when translation is complete'=>'Udgiv kun, når oversættelsen er færdig','Translate by Browsing as User Role'=>'Oversæt ved at gennemse som brugerrolle','Different Menu Items for each Language'=>'Forskellige menupunkter for hvert sprog','Automatic User Language Detection'=>'Automatisk registrering af brugerens sprog','Upgrade to PRO'=>'Opgrader til PRO','Upgrade to PRO with our biggest discount of the year!'=>'Opgrader til PRO med årets største rabat!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Denne Black Friday får du adgang til disse funktioner og mere til en brøkdel af prisen:','No available suggestions'=>'Ingen tilgængelige forslag','Suggestions from translation memory'=>'Forslag fra oversættelseshukommelse','Click to Copy'=>'Klik for at kopiere','Human Translation'=>'Menneskelig oversættelse','Machine Translation'=>'Maskinoversættelse','Text on this page is %s% translated into all languages.'=>'Teksten på denne side er %s% oversat til alle sprog.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% af teksten på denne side er oversat til %2$s.','This page is %1$s% translated into %2$s.'=>'Denne side er %1$s% oversat til %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Den slug, du forsøger at redigere, findes i andre slug-typer: %s%. Redigering af den vil erstatte hver forekomst, uanset den aktuelle type.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Hold musen over en tekst på siden, klik på %s,<br> og rediger derefter oversættelsen i sidebjælken.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Glem ikke at gemme oversættelsen. Brug tastaturgenvejen CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Skift sprog for at se oversættelsesændringerne direkte på siden.','Search for any text in this page in the dropdown.'=>'Søg efter en tekst på denne side i rullemenuen.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Din %s-licens er <span class="trp-license-status-emphasized">udløbet</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Forny din licens for fortsat at have adgang til TranslatePress AI, premium-tilføjelser, automatiske opdateringer og support.','Renew Now'=>'Forny nu','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Forny din licens til en særlig pris denne Black Friday</strong> for fortsat at have adgang til produktdownloads, automatiske opdateringer og support.','Get Deal'=>'Få tilbudet','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Din %s-licens blev <span class="trp-license-status-emphasized">refunderet</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Køb en ny licens for fortsat at have adgang til TranslatePress AI, premium-tilføjelser, automatiske opdateringer og support.','Purchase a new license'=>'Køb en ny licens','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Din %s-licens er <span class="trp-license-status-emphasized">manglende eller ugyldig</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Indtast en gyldig licens for at få adgang til TranslatePress AI, premium-tilføjelser, automatiske opdateringer og support. Har du brug for en licensnøgle? %1$sKøb en nu%2$s','Enter a valid license'=>'Indtast en gyldig licens','Slugs'=>'Slugs','Meta Information'=>'Metadata','String List'=>'Strengliste','Gettext Strings'=>'Gettext-strenge','Images'=>'Billeder','Videos'=>'Videoer','Audios'=>'Lydfiler','Dynamically Added Strings'=>'Dynamisk tilføjede strenge','Translation Editor'=>'Oversættelseseditor','